head.script:
scwin.openPopupInWFrame = function() {
    $p.openPopup("/sample/common_link/util_createPopup_1.xml", {
        id: "popup_wframe",
        type: "iframePopup",
        width: "300px",
        height: "200px",
        top: "150px",
        left: "300px",
        popupName: "popup_wframe (WFrame 내부)",
        modal: false
    });
};
